window.ASBAB_NUZUL_CACHE["53"] = {"mapping_ayat":{"53:8":[{"p":"Muslim","n":257,"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا زَكَرِيَّاءُ عَنْ ابْنِ أَشْوَعَ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَفَأَيْنَ قَوْله{ ثُمَّ دَنَا فَتَدَلَّى فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }قَالَتْ إِنَّمَا ذَاكَ جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِيهِ فِي صُورَةِ الرِّجَالِ وَإِنَّهُ أَتَاهُ فِي هَذِهِ الْمَرَّةِ فِي صُورَتِهِ الَّتِي هِيَ صُورَتُهُ فَسَدَّ أُفُقَ السَّمَاءِ","trj":"Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Zakariya'] dari [Ibnu Asywa'] dari [Amir] dari [Masruq] dia berkata, \"Aku berkata kepada [Aisyah], 'Lalu kita apakah firman Allah: '(Kemudian dia mendekat, lalu bertambah dekat lagi, maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi). Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan) ' (Qs. an-Najm: 8-10). Aisyah menjawab, '(Yang dimaksud ayat tersebut) adalah Jibril. Dia mendatangi Rasulullah dalam bentuk seorang laki-laki, dan pada kesempatan ini, dia mendatangi beliau dalam bentuknya yang sesungguhnya, sehingga dia menutupi ufuk langit'.\""}],"53:9":[{"p":"Muslim","n":250,"ar":"و حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا عَبَّادٌ وَهُوَ ابْنُ الْعَوَّامِ حَدَّثَنَا الشَّيْبَانِيُّ قَالَ سَأَلْتُ زِرَّ بْنَ حُبَيْشٍ عَنْ قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى }قَالَ أَخْبَرَنِي ابْنُ مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى جِبْرِيلَ لَهُ سِتُّ مِائَةِ جَنَاحٍ","trj":"Dan telah menceritakan kepada kami [Abu ar-Rabi' az-Zahrani] telah menceritakan kepada kami [Abbad] -yaitu Ibnu al-Awwam- telah menceritakan kepada kami [asy-Syaibani] dia berkata, \"Aku bertanya kepada [Zir bin Hubaisy] tentang firman Alah: '(Sehingga menjadilah jarak antara dia dengan Nabi Muhammad sejauh dua ujung busur panah atau lebih dekat lagi) ' (Qs. An Najm: 9). Perawi berkata, \" [Ibnu Mas'ud] mengabarkan kepadaku bahwa Nabi shallallahu 'alaihi wasallam melihat Jibril, ia mempunyai enam ratus sayap.\""},{"p":"Muslim","n":257,"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا زَكَرِيَّاءُ عَنْ ابْنِ أَشْوَعَ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَفَأَيْنَ قَوْله{ ثُمَّ دَنَا فَتَدَلَّى فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }قَالَتْ إِنَّمَا ذَاكَ جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِيهِ فِي صُورَةِ الرِّجَالِ وَإِنَّهُ أَتَاهُ فِي هَذِهِ الْمَرَّةِ فِي صُورَتِهِ الَّتِي هِيَ صُورَتُهُ فَسَدَّ أُفُقَ السَّمَاءِ","trj":"Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Zakariya'] dari [Ibnu Asywa'] dari [Amir] dari [Masruq] dia berkata, \"Aku berkata kepada [Aisyah], 'Lalu kita apakah firman Allah: '(Kemudian dia mendekat, lalu bertambah dekat lagi, maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi). Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan) ' (Qs. an-Najm: 8-10). Aisyah menjawab, '(Yang dimaksud ayat tersebut) adalah Jibril. Dia mendatangi Rasulullah dalam bentuk seorang laki-laki, dan pada kesempatan ini, dia mendatangi beliau dalam bentuknya yang sesungguhnya, sehingga dia menutupi ufuk langit'.\""},{"p":"Tirmidzi","n":3031,"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِ اللَّهِ{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى عِنْدَ سِدْرَةِ الْمُنْتَهَى }{ فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى }قَالَ ابْنُ عَبَّاسٍ قَدْ رَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Ibnu Abbas] mengenai firman Allah: \"Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain, (yaitu) di Sidratil Muntaha\" (QS. Nnajm 13-14) \"Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan.\" (QS. ANnajm; 10) \"Maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi).\" (QS. Annajm 9), Ibnu Abbas berkata; Nabi shallallahu 'alaihi wasallam telah melihatNya. Abu Isa berkata; hadits ini adalah hadits hasan."}],"53:10":[{"p":"Muslim","n":257,"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا زَكَرِيَّاءُ عَنْ ابْنِ أَشْوَعَ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَفَأَيْنَ قَوْله{ ثُمَّ دَنَا فَتَدَلَّى فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }قَالَتْ إِنَّمَا ذَاكَ جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِيهِ فِي صُورَةِ الرِّجَالِ وَإِنَّهُ أَتَاهُ فِي هَذِهِ الْمَرَّةِ فِي صُورَتِهِ الَّتِي هِيَ صُورَتُهُ فَسَدَّ أُفُقَ السَّمَاءِ","trj":"Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Zakariya'] dari [Ibnu Asywa'] dari [Amir] dari [Masruq] dia berkata, \"Aku berkata kepada [Aisyah], 'Lalu kita apakah firman Allah: '(Kemudian dia mendekat, lalu bertambah dekat lagi, maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi). Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan) ' (Qs. an-Najm: 8-10). Aisyah menjawab, '(Yang dimaksud ayat tersebut) adalah Jibril. Dia mendatangi Rasulullah dalam bentuk seorang laki-laki, dan pada kesempatan ini, dia mendatangi beliau dalam bentuknya yang sesungguhnya, sehingga dia menutupi ufuk langit'.\""}],"53:11":[{"p":"Muslim","n":251,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الشَّيْبَانِيِّ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِقَالَ{ مَا كَذَبَ الْفُؤَادُ مَا رَأَى }قَالَ رَأَى جِبْرِيلَ عَلَيْهِ السَّلَام لَهُ سِتُّ مِائَةِ جَنَاحٍ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [asy-Syaibani] dari [Zirr] dari [Abdullah] dia berkata tentang firman-Nya: '(Hatinya tidak mendustakan sesuatu yang telah dia lihat) ' (Qs. An Najm: 11). Ibnu Mas'ud berkata, \"Nabi shallallahu 'alaihi wasallam melihat Jibril mempunyai enam ratus sayap.\""},{"p":"Tirmidzi","n":3032,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ أَبِي رِزْمَةَ وَأَبُو نُعَيْمٍ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ مَا كَذَبَ الْفُؤَادُ مَا رَأَى }قَالَ رَآهُ بِقَلْبِهِقَالَ هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abdur Razzaq] dan [Ibnu Abu Rizmah] serta [Abu Nu'aim] dari [Israil] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas], ia berkomentar tentang ayat; \"Hatinya tidak mendustakan apa yang telah dilihatnya.\" (QS. ANnajm 11), Ia berkata; ia melihatNya dengan hatinya. Abu Isa berkata; hadits hasan."},{"p":"Tirmidzi","n":3034,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى وَابْنُ أَبِي رِزْمَةَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ{ مَا كَذَبَ الْفُؤَادُ مَا رَأَى }قَالَ رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِبْرِيلَ فِي حُلَّةٍ مِنْ رَفْرَفٍ قَدْ مَلَأَ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abdu bin Humaid] telah menceritakan kepada kami ['Ubaidullah bin Musa] serta [Ibnu Abu Rizmah] dari [Israil] dari [Abu Ishaq] dari [Abdur Rahman bin Yazid] dari [Abdullah], mengenai ayat; \"Hatinya tidak mendustakan apa yang telah dilihatnya.\" (QS. ANnajm 11), Ia berkata; Rasulullah shallallahu 'alaihi wasallam melihat Jibril memakai perhiasan dari permadani yang telah memenuhi antara langit dan bumi. Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"53:13":[{"p":"Muslim","n":252,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ سَمِعَ زِرَّ بْنَ حُبَيْشٍ عَنْ عَبْدِ اللَّهِقَالَ{ لَقَدْ رَأَى مِنْ آيَاتِ رَبِّهِ الْكُبْرَى }قَالَ رَأَى جِبْرِيلَ فِي صُورَتِهِ لَهُ سِتُّ مِائَةِ جَنَاحٍ","trj":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz al-Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman asy-Syaibani] dia mendengar [Zirr bin Hubaisy] dari [Abdullah] dia berkata tentang firman-Nya: '(Sungguh dia telah melihat ayat-ayat Rabbnya yang agung) ' (Qs. An Najm: 13). Ibnu Mas'ud berkata, \"Nabi shallallahu 'alaihi wasallam telah melihat Jibril dalam bentuk (asli) nya, dia mempunyai enam ratus sayap.\""},{"p":"Muslim","n":253,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }قَالَ رَأَى جِبْرِيلَ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Abdul Malik] dari [Atha'] dari [Abu Hurairah] tentang firman Allah: (Sungguh dia telah melihat ayat-ayat Rabbnya yang agung) ' (Qs. An Najm: 13). Abu Hurairah berkata, \"Beliau melihat malaikat Jibril.\""},{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."},{"p":"Tirmidzi","n":3031,"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِ اللَّهِ{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى عِنْدَ سِدْرَةِ الْمُنْتَهَى }{ فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى }قَالَ ابْنُ عَبَّاسٍ قَدْ رَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Ibnu Abbas] mengenai firman Allah: \"Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain, (yaitu) di Sidratil Muntaha\" (QS. Nnajm 13-14) \"Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan.\" (QS. ANnajm; 10) \"Maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi).\" (QS. Annajm 9), Ibnu Abbas berkata; Nabi shallallahu 'alaihi wasallam telah melihatNya. Abu Isa berkata; hadits ini adalah hadits hasan."}],"53:14":[{"p":"Tirmidzi","n":3031,"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِ اللَّهِ{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى عِنْدَ سِدْرَةِ الْمُنْتَهَى }{ فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى }قَالَ ابْنُ عَبَّاسٍ قَدْ رَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Ibnu Abbas] mengenai firman Allah: \"Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain, (yaitu) di Sidratil Muntaha\" (QS. Nnajm 13-14) \"Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan.\" (QS. ANnajm; 10) \"Maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi).\" (QS. Annajm 9), Ibnu Abbas berkata; Nabi shallallahu 'alaihi wasallam telah melihatNya. Abu Isa berkata; hadits ini adalah hadits hasan."}],"53:16":[{"p":"Muslim","n":249,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالَ ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ إِلَيْهَا يَنْتَهِي مَا يُعْرَجُ بِهِ مِنْ الْأَرْضِ فَيُقْبَضُ مِنْهَا وَإِلَيْهَا يَنْتَهِي مَا يُهْبَطُ بِهِ مِنْ فَوْقِهَا فَيُقْبَضُ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ قَالَ فَأُعْطِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا أُعْطِيَ الصَّلَوَاتِ الْخَمْسَ وَأُعْطِيَ خَوَاتِيمَ سُورَةِ الْبَقَرَةِ وَغُفِرَ لِمَنْ لَمْ يُشْرِكْ بِاللَّهِ مِنْ أُمَّتِهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Malik bin Mighwal]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ibnu Numair] dan [Zuhair bin Harb] semuanya dari [Abdullah bin Numair] dan lafazh mereka saling berdekatan. [Ibnu Numair] berkata, telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Malik bin Mighwal] dari [az-Zubair bin Adi] dari [Thalhah] dari [Murrah] dari [Abdullah] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan maka beliau dihentikan di Sidrah al-Muntaha, (yaitu tempat) yang terletak di langit keenam. Sesuatu yang naik dari bumi akan bermuara di sana dan ditahan padanya. Dan sesuatu dari atasnya berhenti padanya, lalu ditahan padanya.\" Allah berfirman: '(Muhammad melihat Jibril) ketika Sidratil Muntaha diliputi oleh sesuatu yang meliputinya) ' (Qs. An Najm: 16). Abdullah berkata lagi, \"Yaitu hamparan dari emas.\" Dia berkata lagi, \"Lalu Rasulullah shallallahu 'alaihi wasallam diberi tiga hal: shalat lima waktu, ayat-ayat penutup surat al-Baqarah, dan diampuni dosa-dosa besar milik orang yang tidak mensyirikkan Allah dengan sesuatu pun dari kalangan umat beliau.\""},{"p":"Nasa'i","n":446,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ وَإِلَيْهَا يَنْتَهِي مَا عُرِجَ بِهِ مِنْ تَحْتِهَا وَإِلَيْهَا يَنْتَهِي مَا أُهْبِطَ بِهِ مِنْ فَوْقِهَا حَتَّى يُقْبَضَ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ فَأُعْطِيَ ثَلَاثًا الصَّلَوَاتُ الْخَمْسُ وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ وَيُغْفَرُ لِمَنْ مَاتَ مِنْ أُمَّتِهِ لَا يُشْرِكُ بِاللَّهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Yahya bin Adam] dia berkata; Telah menceritakan kepada kami [Malik bin Mighwal] dari [Zubair bin 'Adi] dari [Thalhah bin Musharrif] dari [Murrah] dari [Abdulah] dia berkata; \" Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan beliau sampai ke Sidratul Muntaha, yaitu satu tempat di langit yang ke enam dan sampai di situlah berakhirnya semua yang naik dari bawah dan sampai di situ pula semua yang turun dari atas hingga dapat terpegang. Nabi shallallahu 'alaihi wasallam kemudian membacakan ayat: \"Ketika Sidratul Muntaha diliputi oleh sesuatu yang meliputinya\" (Qs. An-Najm (53): 16) Rasulullah shallallahu 'alaihi wasallam bersabda: \" (Yang meliputi Sidratul Muntaha) adalah kupu-kupu dari emas, lalu aku diberi tiga hal, yaitu shalat lima waktu, akhir-akhir surat Al Baqarah, dan orang yang mati dari umatku diampuni, asalkan tidak menyekutukan Allah Azza Wa Jalla dengan sesuatupun.\" "}],"53:23":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}],"53:32":[{"p":"Tirmidzi","n":3035,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ الْبَصْرِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ{ الَّذِينَ يَجْتَنِبُونَ كَبَائِرَ الْإِثْمِ وَالْفَوَاحِشَ إِلَّا اللَّمَمَ }قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ تَغْفِرْ اللَّهُمَّ تَغْفِرْ جَمَّاوَأَيُّ عَبْدٍ لَكَ لَا أَلَمَّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ زَكَرِيَّا بْنِ إِسْحَقَ","trj":"Telah menceritakan kepada kami [Ahmad bin Utsman Al Bashri] telah menceritakan kepada kami [Abu 'Ashim] dari [Zakariya bin Ishaq] dari ['Amr bin Dinar] dari ['Atho`] dari [Ibnu Abbas] mengenai ayat: \"(Yaitu) orang-orang yang menjauhi dosa-dosa besar dan perbuatan keji yang selain dari kesalahan-kesalahan kecil.\" (QS. Annajm 32), Ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Ya Allah, apabila engkau mengampuni maka Engkau banyak mengampuni, siapakah hamba yang tidak pernah melakukan dosa-dosa kecil?\" Abu Isa berkata; hadits ini adalah hadits hasan shahih gharib, kami tidak mengetahuinya kecuali dari hadits Zakariya bin Ishaq."}],"53:37":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""}],"53:38":[{"p":"Bukhari","n":1206,"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَتُوُفِّيَتْ ابْنَةٌ لِعُثْمَانَ رَضِيَ اللَّهُ عَنْهُ بِمَكَّةَ وَجِئْنَا لِنَشْهَدَهَا وَحَضَرَهَا ابْنُ عُمَرَ وَابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ وَإِنِّي لَجَالِسٌ بَيْنَهُمَا أَوْ قَالَ جَلَسْتُ إِلَى أَحَدِهِمَا ثُمَّ جَاءَ الْآخَرُ فَجَلَسَ إِلَى جَنْبِي فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا لِعَمْرِو بْنِ عُثْمَانَ أَلَا تَنْهَى عَنْ الْبُكَاءِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِفَقَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَدْ كَانَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَقُولُ بَعْضَ ذَلِكَ ثُمَّ حَدَّثَ قَالَ صَدَرْتُ مَعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ مِنْ مَكَّةَ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ إِذَا هُوَ بِرَكْبٍ تَحْتَ ظِلِّ سَمُرَةٍ فَقَالَ اذْهَبْ فَانْظُرْ مَنْ هَؤُلَاءِ الرَّكْبُ قَالَ فَنَظَرْتُ فَإِذَا صُهَيْبٌ فَأَخْبَرْتُهُ فَقَالَ ادْعُهُ لِي فَرَجَعْتُ إِلَى صُهَيْبٍ فَقُلْتُ ارْتَحِلْ فَالْحَقْ أَمِيرَ الْمُؤْمِنِينَ فَلَمَّا أُصِيبَ عُمَرُ دَخَلَ صُهَيْبٌ يَبْكِي يَقُولُ وَا أَخَاهُ وَا صَاحِبَاهُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَا صُهَيْبُ أَتَبْكِي عَلَيَّ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ يُعَذَّبُ بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَلَمَّا مَاتَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ ذَكَرْتُ ذَلِكَ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْ رَحِمَ اللَّهُ عُمَرَ وَاللَّهِ مَا حَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَيُعَذِّبُ الْمُؤْمِنَ بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيَزِيدُ الْكَافِرَ عَذَابًا بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَقَالَتْ حَسْبُكُمْ الْقُرْآنُ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عِنْدَ ذَلِكَ وَاللَّهُ{ هُوَ أَضْحَكَ وَأَبْكَى }قَالَ ابْنُ أَبِي مُلَيْكَةَ وَاللَّهِ مَا قَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا شَيْئًا","trj":"Telah menceritakan kepada kami ['Abdan] telah menceritakan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Abdullah bin 'ubaidullah bin Abu Mulaikah] berkata; \"Telah wafat isteri 'Utsman radliallahu 'anha di Makkah lalu kami datang menyaksikan (pemakamannya). Hadir pula Ibnu 'Umar dan Ibnu 'Abbas radliallahu 'anhum dan saat itu aku duduk diantara keduanya\". Atau katanya: \"Aku duduk dekat salah satu dari keduanya\". Kemudian datang orang lain lalu duduk di sampingku. Berkata, [Ibnu 'Umar radliallahu 'anhuma] kepada 'Amru bin 'Utsman: \"Bukankan dilarang menangis dan sungguh Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan tangisan keluarganya kepadanya?\". Maka [Ibnu 'Abbas radliallahu 'anhuma] berkata,: \"Sungguh 'Umar radliallahu 'anhu pernah mengatakan sebagiannya dari hal tadi\". Kemudian dia menceritakan, katanya: \"Aku pernah bersama 'Umar radliallahu 'anhu dari kota Makkah hingga kami sampai di Al Baida, di tempat itu dia melihat ada orang yang menunggang hewan tunggangannya di bawah pohon. Lalu dia berkata,: \"Pergi dan lihatlah siapa mereka yang menunggang hewan tunggangannya itu!\". Maka aku datang melihatnya yang ternyata dia adalah Shuhaib. Lalu aku kabarkan kepadanya. Dia (\"Umar) berkata,: \"Panggillah dia kemari!\". Aku kembali menemui Shuhaib lalu aku berkata: \"Pergi dan temuilah Amirul Mu'minin\". Kemudian hari 'Umar mendapat musibah dibunuh orang, Shuhaib mendatanginya sambil menangis sambil terisak berkata,: Wahai saudaraku, wahai sahabat\". Maka ['Umar] berkata,: \"Wahai Shuhaib, mengapa kamu menangis untukku padahal Nabi Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan sebagian tangisan keluarganya \". Berkata, [Ibnu 'Abbas radliallahu 'anhuma]: \"Ketika 'Umar sudah wafat aku tanyakan masalah ini kepada ['Aisyah] radliallahu 'anha, maka dia berkata,: \"Semoga Allah merahmati 'Umar. Demi Allah, tidaklah Rasulullah Shallallahu'alaihiwasallam pernah berkata seperti itu, bahwa Allah pasti akan menyiksa orang beriman disebabkan tangisan keluarganya kepadanya, akan tetapi yang benar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya Allah pasti akan menambah siksaan buat orang kafir disebabkan tangisan keluarganya kepadanya\". Dan cukuplah buat kalian firman Allah) dalam AL Qur'an (QS. An-Najm: 38) yang artinya: \"Dan tidaklah seseorang memikul dosa orang lain\". Ibnu 'Abbas radliallahu 'anhu berkata seketika itu pula: Dan Allahlah yang menjadikan seseorang tertawa dan menangis\" (QS. Annajm 43). Berkata Ibnu Abu Mulaikah: \"Demi Allah, setelah itu Ibnu 'Umar radliallahu 'anhu tidak mengucapkan sepatah kata pun\"."},{"p":"Tirmidzi","n":925,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلَّبِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِ فَقَالَتْ عَائِشَةُ يَرْحَمُهُ اللَّهُ لَمْ يَكْذِبْ وَلَكِنَّهُ وَهِمَ إِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مَاتَ يَهُودِيًّا إِنَّ الْمَيِّتَ لَيُعَذَّبُ وَإِنَّ أَهْلَهُ لَيَبْكُونَ عَلَيْهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَقَرَظَةَ بْنِ كَعْبٍ وَأَبِي هُرَيْرَةَ وَابْنِ مَسْعُودٍ وَأُسَامَةَ بْنِ زَيْدٍ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عَائِشَةَ وَقَدْ ذَهَبَ أَهْلُ الْعِلْمِ إِلَى هَذَا وَتَأَوَّلُوا هَذِهِ الْآيَةَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }وَهُوَ قَوْلُ الشَّافِعِيِّ","trj":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami ['Abbad bin 'Abbad Al Muhallabi] dari [Muhammad bin 'Amr] dari [Yahya bin Abdurrahman] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya mayit itu diadzab karena tangisan keluarganya atas (kematian) nya.\" ['Aisyah] berkata; -Semoga Allah merahmati (Ibnu Umar) - dia tidak bohong namun salah mengucapkan, sebenarnya Rasulullah shallallahu 'alaihi wasallam berkata demikian kepada seorang lelaki yang mati dalam agama Yahudi yaitu sabda beliau, \"Sesungguhnya si mayit ini akan diadzab, dan keluarganya akan menangisinya.\" Hadits semakna diriwayatkan dari Ibnu Abbas, Qaradlah bin Ka'ab, Abu Hurairah, Ibnu Mas'ud dan Usamah bin Zaid. Abu 'Isa berkata; \"Hadits 'Aisyah merupakan hadits hasan shohih dan hadits ini telah diriwayatkan melalui lebih dari satu jalur dari 'Aisyah. Sebagian ulama yaitu Syafi'i berpendapat berdasarkan hadits ini dengan menta'wilkan ayat; \"Bahwasanya seorang yang berdosa tidak akan memikul dosa orang lain.\" (Qs. An Najm: 38) "}],"53:43":[{"p":"Bukhari","n":1206,"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَتُوُفِّيَتْ ابْنَةٌ لِعُثْمَانَ رَضِيَ اللَّهُ عَنْهُ بِمَكَّةَ وَجِئْنَا لِنَشْهَدَهَا وَحَضَرَهَا ابْنُ عُمَرَ وَابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ وَإِنِّي لَجَالِسٌ بَيْنَهُمَا أَوْ قَالَ جَلَسْتُ إِلَى أَحَدِهِمَا ثُمَّ جَاءَ الْآخَرُ فَجَلَسَ إِلَى جَنْبِي فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا لِعَمْرِو بْنِ عُثْمَانَ أَلَا تَنْهَى عَنْ الْبُكَاءِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِفَقَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَدْ كَانَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَقُولُ بَعْضَ ذَلِكَ ثُمَّ حَدَّثَ قَالَ صَدَرْتُ مَعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ مِنْ مَكَّةَ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ إِذَا هُوَ بِرَكْبٍ تَحْتَ ظِلِّ سَمُرَةٍ فَقَالَ اذْهَبْ فَانْظُرْ مَنْ هَؤُلَاءِ الرَّكْبُ قَالَ فَنَظَرْتُ فَإِذَا صُهَيْبٌ فَأَخْبَرْتُهُ فَقَالَ ادْعُهُ لِي فَرَجَعْتُ إِلَى صُهَيْبٍ فَقُلْتُ ارْتَحِلْ فَالْحَقْ أَمِيرَ الْمُؤْمِنِينَ فَلَمَّا أُصِيبَ عُمَرُ دَخَلَ صُهَيْبٌ يَبْكِي يَقُولُ وَا أَخَاهُ وَا صَاحِبَاهُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَا صُهَيْبُ أَتَبْكِي عَلَيَّ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ يُعَذَّبُ بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَلَمَّا مَاتَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ ذَكَرْتُ ذَلِكَ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْ رَحِمَ اللَّهُ عُمَرَ وَاللَّهِ مَا حَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَيُعَذِّبُ الْمُؤْمِنَ بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيَزِيدُ الْكَافِرَ عَذَابًا بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَقَالَتْ حَسْبُكُمْ الْقُرْآنُ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عِنْدَ ذَلِكَ وَاللَّهُ{ هُوَ أَضْحَكَ وَأَبْكَى }قَالَ ابْنُ أَبِي مُلَيْكَةَ وَاللَّهِ مَا قَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا شَيْئًا","trj":"Telah menceritakan kepada kami ['Abdan] telah menceritakan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Abdullah bin 'ubaidullah bin Abu Mulaikah] berkata; \"Telah wafat isteri 'Utsman radliallahu 'anha di Makkah lalu kami datang menyaksikan (pemakamannya). Hadir pula Ibnu 'Umar dan Ibnu 'Abbas radliallahu 'anhum dan saat itu aku duduk diantara keduanya\". Atau katanya: \"Aku duduk dekat salah satu dari keduanya\". Kemudian datang orang lain lalu duduk di sampingku. Berkata, [Ibnu 'Umar radliallahu 'anhuma] kepada 'Amru bin 'Utsman: \"Bukankan dilarang menangis dan sungguh Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan tangisan keluarganya kepadanya?\". Maka [Ibnu 'Abbas radliallahu 'anhuma] berkata,: \"Sungguh 'Umar radliallahu 'anhu pernah mengatakan sebagiannya dari hal tadi\". Kemudian dia menceritakan, katanya: \"Aku pernah bersama 'Umar radliallahu 'anhu dari kota Makkah hingga kami sampai di Al Baida, di tempat itu dia melihat ada orang yang menunggang hewan tunggangannya di bawah pohon. Lalu dia berkata,: \"Pergi dan lihatlah siapa mereka yang menunggang hewan tunggangannya itu!\". Maka aku datang melihatnya yang ternyata dia adalah Shuhaib. Lalu aku kabarkan kepadanya. Dia (\"Umar) berkata,: \"Panggillah dia kemari!\". Aku kembali menemui Shuhaib lalu aku berkata: \"Pergi dan temuilah Amirul Mu'minin\". Kemudian hari 'Umar mendapat musibah dibunuh orang, Shuhaib mendatanginya sambil menangis sambil terisak berkata,: Wahai saudaraku, wahai sahabat\". Maka ['Umar] berkata,: \"Wahai Shuhaib, mengapa kamu menangis untukku padahal Nabi Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan sebagian tangisan keluarganya \". Berkata, [Ibnu 'Abbas radliallahu 'anhuma]: \"Ketika 'Umar sudah wafat aku tanyakan masalah ini kepada ['Aisyah] radliallahu 'anha, maka dia berkata,: \"Semoga Allah merahmati 'Umar. Demi Allah, tidaklah Rasulullah Shallallahu'alaihiwasallam pernah berkata seperti itu, bahwa Allah pasti akan menyiksa orang beriman disebabkan tangisan keluarganya kepadanya, akan tetapi yang benar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya Allah pasti akan menambah siksaan buat orang kafir disebabkan tangisan keluarganya kepadanya\". Dan cukuplah buat kalian firman Allah) dalam AL Qur'an (QS. An-Najm: 38) yang artinya: \"Dan tidaklah seseorang memikul dosa orang lain\". Ibnu 'Abbas radliallahu 'anhu berkata seketika itu pula: Dan Allahlah yang menjadikan seseorang tertawa dan menangis\" (QS. Annajm 43). Berkata Ibnu Abu Mulaikah: \"Demi Allah, setelah itu Ibnu 'Umar radliallahu 'anhu tidak mengucapkan sepatah kata pun\"."}],"53:51":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}]},"mapping_surah":[{"p":"Abu Dawud","n":1167,"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَرَأْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ فَلَمْ يَسْجُدْ فِيهَاحَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنَا أَبُو صَخْرٍ عَنْ ابْنِ قُسَيْطٍ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد كَانَ زَيْدٌ الْإِمَامَ فَلَمْ يَسْجُدْ فِيهَا","trj":"Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami [Waki'] dari [Abu Ad Dzi`b] dari [Yazid bin Abdullah bin Qusaith] dari ['Atha` bin Yasar] dari [Zaid bin Tsabit] dia berkata; \"Aku pernah membaca surat An Najm di hadapan Rasulullah shallallahu 'alaihi wasallam, namun beliau tidak sujud.\" Telah menceritakan kepada kami [Ibnu As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Abu Shakhr] dari [Ibnu Qusaith] dari [Kharijah bin Zaid bin Tsabit] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam semakna dengan hadits di atas. Abu Daud berkata; \"Zaid adalah seorang Imam, namun dia tidak sujud ketika membaca surat tersebut.\""},{"p":"Abu Dawud","n":1168,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ سُورَةَ النَّجْمِ فَسَجَدَ فِيهَا وَمَا بَقِيَ أَحَدٌ مِنْ الْقَوْمِ إِلَّا سَجَدَ فَأَخَذَ رَجُلٌ مِنْ الْقَوْمِ كَفًّا مِنْ حَصًى أَوْ تُرَابٍ فَرَفَعَهُ إِلَى وَجْهِهِ وَقَالَ يَكْفِينِي هَذَاقَالَ عَبْدُ اللَّهِ فَلَقَدْ رَأَيْتُهُ بَعْدَ ذَلِكَ قُتِلَ كَافِرًا","trj":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah membaca surat An Najm, lalu beliau sujud, dan tidak seorang pun dari kaum tersebut yang tidak turut sujud. Setelah itu seorang laki-laki dari kaum tersebut mengambil segenggam kerikil atau tanah, lalu di angkat ke wajahnya sambil berkata; \"Sujud bagiku cukuplah sekali ini saja.\" Abdullah berkata; \"Sungguh, setelah peristiwa tersebut, aku melihat laki-laki tersebut mati terbunuh dalam keadaan kafir.\" "},{"p":"Ahmad","n":391,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي النَّجْمِ وَسَجَدَ النَّاسُ مَعَهُقَالَ الْمُطَّلِبُ وَلَمْ أَسْجُدْ مَعَهُمْ وَهُوَ يَوْمَئِذٍ مُشْرِكٌ فَقَالَ الْمُطَّلِبُ فَلَا أَدَعُ السُّجُودَ فِيهَا أَبَدًا","trj":"Telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khalid] dari [Al Muthalib bin Abu Wada'ah] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam sujud karena membaca ayat dalam surat An-Najm, (AN Najm:) lalu orang-orang ikut sujud bersama beliau. Al Muthalib berkata; saya tidak ikut sujud bersama mereka, karena ketika itu dia masih musyrik. Lalu Al Muthalib berkata; namun di kemudian hari saya tidak meninggalkan sujud ketika membacanya selamanya."},{"p":"Ahmad","n":392,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ جَعْفَرِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيِّ عَنْ أَبِيهِ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ سُورَةَ النَّجْمِ فَسَجَدَ وَسَجَدَ مَنْ عِنْدَهُفَرَفَعْتُ رَأْسِي وَأَبَيْتُ أَنْ أَسْجُدَ وَلَمْ يَكُنْ أَسْلَمَ يَوْمَئِذٍ الْمُطَّلِبُ وَكَانَ بَعْدُ لَا يَسْمَعُ أَحَدًا قَرَأَهَا إِلَّا سَجَدَ","trj":"Telah menceritakan kepada kami [Ibrahim bin Khalid] telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khalid] dari [Ja'far bin Abu Wada'ah As-Sahmi] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam di Makkah membaca surat An-Najm lalu beliau bersujud, dan orang-orang yang sedang bersama beliau juga bersujud. Lalu saya mengangkat kepalaku dan saya menolak untuk bersujud. Karena ketika itu Al Muthalib belum masuk Islam. Di kemudian hari, tidaklah ia mendengarkan seorang pun yang membacanya kecuali dia bersujud."},{"p":"Ahmad","n":1824,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي النَّجْمِ وَسَجَدَ النَّاسُ مَعَهُقَالَ الْمُطَّلِبُ وَلَمْ أَسْجُدْ مَعَهُمْ وَهُوَ يَوْمَئِذٍ مُشْرِكٌ قَالَ الْمُطَّلِبُّ فَلَا أَدَعُ السُّجُودَ فِيهَا أَبَدًا","trj":"Telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Ikrimah bin Khalid] dari [Al Muthallib bin Abu Wada'ah] ia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam sujud sahwi dalam surat An Najm, dan orang-orang pun ikut sujud bersama beliau.\" Al Muthallib berkata, \"Namun saya tidak ikut sujud bersama mereka -saat itu ia masih dalam keadaan musyrik-.\" Al Muthallib berkata lagi, \"(Sekarang) selamanya aku tidak akan meninggalkan sujud saat pembacaan surat itu.\""},{"p":"Ahmad","n":1825,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ جَعْفَرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ عَنْ أَبِيهِ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ سُورَةَ النَّجْمِ فَسَجَدَ وَسَجَدَ مَنْ عِنْدَهُ فَرَفَعْتُ رَأْسِي وَأَبَيْتُ أَنْ أَسْجُدَوَلَمْ يَكُنْ أَسْلَمَ يَوْمَئِذٍ الْمُطَّلِبُ وَكَانَ بَعْدَ ذَلِكَ لَا يَسْمَعُ أَحَدًا يَقْرَأُ بِهَا إِلَّا سَجَدَ مَعَهُ","trj":"Telah menceritakan kepada kami [Ibrahim bin Khalid] telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Ibnu Thawus] dari [Ikrimah bin Khalid] dari [Ja'far bin Muthallib bin Abu Wada'ah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca surat An Najm di Makkah, lalu beliau sujud dan orang-orang yang bersamanya pun ikut sujud. Tetapi saya mengangkat kepalaku dan enggan untuk sujud.\" Pada saat itu Al Muthallib belum memeluk Islam, dan setelah memeluk Islam maka tidaklah ia mendengar seseorang membaca surat itu kecuali ia sujud bersanya.\""},{"p":"Ahmad","n":4060,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ جَعْفَرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيِّ عَنْ أَبِيهِ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ سُورَةَ النَّجْمِ فَسَجَدَ فِيهَا وَسَجَدَ مَنْ عِنْدَهُ فَرَفَعْتُ رَأْسِي وَأَبَيْتُ أَنْ أَسْجُدَوَلَمْ يَكُنْ أَسْلَمَ يَوْمَئِذٍ الْمُطَّلِبُ وَكَانَ بَعْدُ لَا يَسْمَعُ أَحَدًا قَرَأَهَا إِلَّا سَجَدَ","trj":"Telah menceritakan kepada kami [Ibrahim bin Khalid] berkata, telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khlaid] dari [Ja'far bin Al Mutthalib bin Abu Wada'ah As Sahmi] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca surat An Najm di Makkah lantas beliau sujud, kemudian orang-orang yang bersama beliau juga ikut sujud, namun aku mengangkat kepalaku dan enggan untuk sujud. Dan Mutthalib pada saat itu belum masuk Islam, akan tetapi setelah itu, tidaklah salah seorang membacanya (surat An Najm) melainkan dia sujud.\""},{"p":"Ahmad","n":4061,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي النَّجْمِ وَسَجَدَ النَّاسُ مَعَهُقَالَ الْمُطَّلِبُ وَلَمْ أَسْجُدْ مَعَهُمْ وَهُوَ يَوْمَئِذٍ مُشْرِكٌ قَالَ الْمُطَّلِبُ وَلَا أَدَعُ السُّجُودَ فِيهَا أَبَدًا","trj":"Telah menceritakan kepada kami ['Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khalid] dari [Al Mutthalib bin Abu Wada'ah] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam sujud dalam surat An Najm, dan orang-orang ikut bersujud bersama beliau, Al Mutthalib berkata, \"Sedangkan aku tidak sujud bersama mereka, \" dan dia (Al Mutthalib) pada saat itu masih musyrik.\" Al Mutthalib berkata, \"Maka aku tidak lagi meninggalkan sujud di dalam (surat An Najm) selamanya.\""},{"p":"Bukhari","n":1005,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْأَسْوَدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ بِمَكَّةَ فَسَجَدَ فِيهَا وَسَجَدَ مَنْ مَعَهُ غَيْرَ شَيْخٍ أَخَذَ كَفًّا مِنْ حَصًى أَوْ تُرَابٍ فَرَفَعَهُ إِلَى جَبْهَتِهِ وَقَالَ يَكْفِينِي هَذَا فَرَأَيْتُهُ بَعْدَ ذَلِكَ قُتِلَ كَافِرًا","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata; aku mendengar [Al Aswad] dari ['Abdullah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam membaca surah An-Najm ketika berada di Makkah. Maka Beliau sujud tilawah begitu juga orang-orang yang bersama Beliau. Kecuali ada seorang yang tua, dia hanya mengambil segenggam kerikil atau tanah lalu menempelkannya pada mukanya seraya berkata; \"bagiku cukup begini\". Di kemudian hari aku melihat orang itu terbunuh dalam kekafiran\"."},{"p":"Bukhari","n":1008,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ سُورَةَ النَّجْمِ فَسَجَدَ بِهَا فَمَا بَقِيَ أَحَدٌ مِنْ الْقَوْمِ إِلَّا سَجَدَ فَأَخَذَ رَجُلٌ مِنْ الْقَوْمِ كَفًّا مِنْ حَصًى أَوْ تُرَابٍ فَرَفَعَهُ إِلَى وَجْهِهِ وَقَالَ يَكْفِينِي هَذَا قَالَ عَبْدُ اللَّهِ فَلَقَدْ رَأَيْتُهُ بَعْدُ قُتِلَ كَافِرًا","trj":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari ['Abdullah radliallahu 'anhu] berkata: \"Bahwa Nabi shallallahu 'alaihi wasallam membaca surah An-Najm lalu Beliau sujud dan tidak ada seorang pun dari kaum saat itu melainkan mengikuti beliau untuk sujud. Kecuali ada seseorang dari mereka yang ia hanya mengambil segenggam kerikil atau tanah lalu menempelkannya pada mukanya seraya berkata; \"bagiku cukup begini\". Berkata, 'Abdullah: Di kemudian hari aku melihat orang itu terbunuh dalam kekafiran\"."},{"p":"Bukhari","n":1009,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ بِالنَّجْمِ وَسَجَدَ مَعَهُ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْجِنُّ وَالْإِنْسُوَرَوَاهُ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَيُّوبَ","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma]: \"Bahwa Nabi shallallahu 'alaihi wasallam melakukan sujud tilawah ketika membaca surah An-Najm. Begitu juga ikut sujud bersama Beliau dari kalangan Kaum Muslimin, Musyrikin, bangsa jin dan manusia. Hadits ini juga diriwayatkan oleh [Ibrahim bin Thahman] dari [Ayyub]."},{"p":"Bukhari","n":1010,"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو الرَّبِيعِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنَا يَزِيدُ بْنُ خُصَيْفَةَ عَنْ ابْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَأَلَ زَيْدَ بْنَ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ فَزَعَمَأَنَّهُ قَرَأَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّجْمِ فَلَمْ يَسْجُدْ فِيهَا","trj":"Telah menceritakan kepada kami [Sulaiman bin Daud Abu Ar-Rabi'] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] berkata, telah mengabarkan kepada kami [Yazid bin Khushaifah] dari [Ibnu Qusaith] dari ['Atho' bin Basar] bahwa dia mengabarkannya, bahwa dia pernah bertanya kepada [Zaid bin Tsabit radliallahu 'anhu] (tentang sujud tilawah pada surah An-Najm). Maka dia menceritakan bahwa dia pernah membaca surah An-Najm untuk Nabi shallallahu 'alaihi wasallam namun Beliau tidak melakukan sujud tilawah padanya\"."},{"p":"Bukhari","n":1011,"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَرَأْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّجْمِ فَلَمْ يَسْجُدْ فِيهَا","trj":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Ibnu Abu Dza'bi] berkata, telah menceritakan kepada kami [Yazid bin 'Abdullah bin Qusaith] dari ['Atho' bin Basar] dari [Zaid bin Tsabit radliallahu 'anhu] berkata: \"Aku pernah membaca surah An-Najm untuk Nabi shallallahu 'alaihi wasallam dan Beliau tidak melakukan sujud tilawah padanya\"."},{"p":"Bukhari","n":1206,"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَتُوُفِّيَتْ ابْنَةٌ لِعُثْمَانَ رَضِيَ اللَّهُ عَنْهُ بِمَكَّةَ وَجِئْنَا لِنَشْهَدَهَا وَحَضَرَهَا ابْنُ عُمَرَ وَابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ وَإِنِّي لَجَالِسٌ بَيْنَهُمَا أَوْ قَالَ جَلَسْتُ إِلَى أَحَدِهِمَا ثُمَّ جَاءَ الْآخَرُ فَجَلَسَ إِلَى جَنْبِي فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا لِعَمْرِو بْنِ عُثْمَانَ أَلَا تَنْهَى عَنْ الْبُكَاءِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِفَقَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَدْ كَانَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَقُولُ بَعْضَ ذَلِكَ ثُمَّ حَدَّثَ قَالَ صَدَرْتُ مَعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ مِنْ مَكَّةَ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ إِذَا هُوَ بِرَكْبٍ تَحْتَ ظِلِّ سَمُرَةٍ فَقَالَ اذْهَبْ فَانْظُرْ مَنْ هَؤُلَاءِ الرَّكْبُ قَالَ فَنَظَرْتُ فَإِذَا صُهَيْبٌ فَأَخْبَرْتُهُ فَقَالَ ادْعُهُ لِي فَرَجَعْتُ إِلَى صُهَيْبٍ فَقُلْتُ ارْتَحِلْ فَالْحَقْ أَمِيرَ الْمُؤْمِنِينَ فَلَمَّا أُصِيبَ عُمَرُ دَخَلَ صُهَيْبٌ يَبْكِي يَقُولُ وَا أَخَاهُ وَا صَاحِبَاهُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَا صُهَيْبُ أَتَبْكِي عَلَيَّ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ يُعَذَّبُ بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَلَمَّا مَاتَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ ذَكَرْتُ ذَلِكَ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْ رَحِمَ اللَّهُ عُمَرَ وَاللَّهِ مَا حَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَيُعَذِّبُ الْمُؤْمِنَ بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيَزِيدُ الْكَافِرَ عَذَابًا بِبُكَاءِ أَهْلِهِ عَلَيْهِ وَقَالَتْ حَسْبُكُمْ الْقُرْآنُ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عِنْدَ ذَلِكَ وَاللَّهُ{ هُوَ أَضْحَكَ وَأَبْكَى }قَالَ ابْنُ أَبِي مُلَيْكَةَ وَاللَّهِ مَا قَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا شَيْئًا","trj":"Telah menceritakan kepada kami ['Abdan] telah menceritakan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Abdullah bin 'ubaidullah bin Abu Mulaikah] berkata; \"Telah wafat isteri 'Utsman radliallahu 'anha di Makkah lalu kami datang menyaksikan (pemakamannya). Hadir pula Ibnu 'Umar dan Ibnu 'Abbas radliallahu 'anhum dan saat itu aku duduk diantara keduanya\". Atau katanya: \"Aku duduk dekat salah satu dari keduanya\". Kemudian datang orang lain lalu duduk di sampingku. Berkata, [Ibnu 'Umar radliallahu 'anhuma] kepada 'Amru bin 'Utsman: \"Bukankan dilarang menangis dan sungguh Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan tangisan keluarganya kepadanya?\". Maka [Ibnu 'Abbas radliallahu 'anhuma] berkata,: \"Sungguh 'Umar radliallahu 'anhu pernah mengatakan sebagiannya dari hal tadi\". Kemudian dia menceritakan, katanya: \"Aku pernah bersama 'Umar radliallahu 'anhu dari kota Makkah hingga kami sampai di Al Baida, di tempat itu dia melihat ada orang yang menunggang hewan tunggangannya di bawah pohon. Lalu dia berkata,: \"Pergi dan lihatlah siapa mereka yang menunggang hewan tunggangannya itu!\". Maka aku datang melihatnya yang ternyata dia adalah Shuhaib. Lalu aku kabarkan kepadanya. Dia (\"Umar) berkata,: \"Panggillah dia kemari!\". Aku kembali menemui Shuhaib lalu aku berkata: \"Pergi dan temuilah Amirul Mu'minin\". Kemudian hari 'Umar mendapat musibah dibunuh orang, Shuhaib mendatanginya sambil menangis sambil terisak berkata,: Wahai saudaraku, wahai sahabat\". Maka ['Umar] berkata,: \"Wahai Shuhaib, mengapa kamu menangis untukku padahal Nabi Shallallahu'alaihiwasallam telah bersabda: \"Sesungguhnya mayat pasti akan disiksa disebabkan sebagian tangisan keluarganya \". Berkata, [Ibnu 'Abbas radliallahu 'anhuma]: \"Ketika 'Umar sudah wafat aku tanyakan masalah ini kepada ['Aisyah] radliallahu 'anha, maka dia berkata,: \"Semoga Allah merahmati 'Umar. Demi Allah, tidaklah Rasulullah Shallallahu'alaihiwasallam pernah berkata seperti itu, bahwa Allah pasti akan menyiksa orang beriman disebabkan tangisan keluarganya kepadanya, akan tetapi yang benar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya Allah pasti akan menambah siksaan buat orang kafir disebabkan tangisan keluarganya kepadanya\". Dan cukuplah buat kalian firman Allah) dalam AL Qur'an (QS. An-Najm: 38) yang artinya: \"Dan tidaklah seseorang memikul dosa orang lain\". Ibnu 'Abbas radliallahu 'anhu berkata seketika itu pula: Dan Allahlah yang menjadikan seseorang tertawa dan menangis\" (QS. Annajm 43). Berkata Ibnu Abu Mulaikah: \"Demi Allah, setelah itu Ibnu 'Umar radliallahu 'anhu tidak mengucapkan sepatah kata pun\"."},{"p":"Bukhari","n":3407,"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ فَسَجَدَ فَمَا بَقِيَ أَحَدٌ إِلَّا سَجَدَ إِلَّا رَجُلٌ رَأَيْتُهُ أَخَذَ كَفًّا مِنْ حَصًا فَرَفَعَهُ فَسَجَدَ عَلَيْهِ وَقَالَ هَذَا يَكْفِينِي فَلَقَدْ رَأَيْتُهُ بَعْدُ قُتِلَ كَافِرًا بِاللَّهِ","trj":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam membaca surah an Najm lalu sujud (tilawah) dan tidak ada seorangpun melainkan ikut sujud kecuali seseorang yang aku lihat dia mengambil segenggam kerikil lalu mengangkatnya lalu sujud (menempelkannya ke keningnya) sambil berkata; \"Bagiku ini sudah cukup\". Sungguh aku melihat orang itu (di kemudian hari) terbunuh dalam keadaan kufur kepada Allah\"."},{"p":"Bukhari","n":4179,"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّجْمِ وَسَجَدَ مَعَهُ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْجِنُّ وَالْإِنْسُتَابَعَهُ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَيُّوبَ وَلَمْ يَذْكُرِ ابْنُ عُلَيَّةَ ابْنَ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami ['Abdul Warits] Telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; \"Nabi shallallahu 'alaihi wasallam bersujud pada surat An Najm, demikian juga kaum muslimin, orang-orang musyrik, jin dan seluruh manusia yang hadir.\" Hal ini diriwayatkan pula oleh [Ibrahim bin Thahman] dari [Ayyub], namun [Ibnu 'Ulayyah] tidak menyebutkan Ibnu Abbas."},{"p":"Bukhari","n":4180,"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنِي أَبُو أَحْمَدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَأَوَّلُ سُورَةٍ أُنْزِلَتْ فِيهَا سَجْدَةٌ وَالنَّجْمِ قَالَ فَسَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَجَدَ مَنْ خَلْفَهُ إِلَّا رَجُلًا رَأَيْتُهُ أَخَذَ كَفًّا مِنْ تُرَابٍ فَسَجَدَ عَلَيْهِ فَرَأَيْتُهُ بَعْدَ ذَلِكَ قُتِلَ كَافِرًا وَهُوَ أُمَيَّةُ بْنُ خَلَفٍ","trj":"Telah menceritakan kepada kami [Nashr bin Ali] Telah mengabarkan kepadaku [Abu Ahmad] Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dari [Abdullah radliallahu 'anhu] dia berkata; Surat pertama kali yang di dalamnya ada ayat sajdah adalah surat An Najm. Abdullah berkata; Maka Rasulullah shallallahu 'alaihi wasallam dan orang-orang yang berada dibelakang beliau pun bersujud, kecuali seorang laki-laki yang aku lihat ia mengambil segenggam tanah lalu ia bersujud di atasnya. Setelah itu aku melihat orang itu terbunuh dalam keadaan kafir. Ia adalah Umayyah bin Khalaf."},{"p":"Darimi","n":1076,"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ النَّجْمَ فَسَجَدَ فِيهَا وَلَمْ يَبْقَ أَحَدٌ إِلَّا سَجَدَ إِلَّا شَيْخٌ أَخَذَ كَفًّا مِنْ حَصًى فَرَفَعَهُ إِلَى جَبْهَتِهِ وَقَالَ يَكْفِينِي هَذَا","trj":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah bin Mas'ud], bahwa Rasulullah shallallahu 'alaihi wasallam saat membaca surat An Najm beliau sujud, dan tidak ada seorangpun melainkan ia ikut sujud kecuali seorang laki-laki tua, ia mengambil satu genggam pasir kemudian menempelkannya pada kening seraya berkata, 'Ini cukup bagiku'.\""},{"p":"Darimi","n":1083,"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ قَرَأْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ فَلَمْ يَسْجُدْ فِيهَا","trj":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Ibnu Abu Dzi`b] dari [Yazid bin Abdullah bin Qusaith] dari ['Atha` bin Yasar] dari [Zaid bin Tsabit] ia berkata, \"Aku membaca surat An Najm di sisi Rasulullah shallallahu 'alaihi wasallam, dan beliau tidak sujud padanya.\" "},{"p":"Ibnu Majah","n":1012,"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ عُمَرَ الدِّمَشْقِيِّ عَنْ أُمِّ الدَّرْدَاءِ قَالَتْ حَدَّثَنِي أَبُو الدَّرْدَاءِأَنَّهُ سَجَدَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى عَشْرَةَ سَجْدَةً مِنْهُنَّ النَّجْمُ","trj":"Telah menceritakan kepada kami [Harmalah bin Yahya Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Amru Ibnul Harits] dari [Ibnu Abu Hilal] dari [Umar Ad Dimasyqi] dari [Ummu Darda] ia berkata, \" [Abu Darda] menceritakan kepadaku bahwa ia pernah sujud bersama Nabi shallallahu 'alaihi wasallam sebanyak sebelas kali, salah satunya adalah dalam surat An Najm. \""},{"p":"Malik","n":429,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ أَنَّ عُمَرَ بْنَ الْخَطَّابِقَرَأَ بِالنَّجْمِ إِذَا هَوَى فَسَجَدَ فِيهَ�� ثُمَّ قَامَ فَقَرَأَ بِسُورَةٍ أُخْرَى","trj":"Telah menceritakan kepadaku dari Malik dari [Ibnu Syihab] dari [Al A'raj] bahwa [Umar bin Khatthab] membaca surat An-Najm; IDZA HAWA (dalam shalatnya), lalu dia sujud karenanya. Kemudian dia berdiri lagi dan membaca surat yang lain.\""},{"p":"Muslim","n":249,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالَ ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ إِلَيْهَا يَنْتَهِي مَا يُعْرَجُ بِهِ مِنْ الْأَرْضِ فَيُقْبَضُ مِنْهَا وَإِلَيْهَا يَنْتَهِي مَا يُهْبَطُ بِهِ مِنْ فَوْقِهَا فَيُقْبَضُ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ قَالَ فَأُعْطِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا أُعْطِيَ الصَّلَوَاتِ الْخَمْسَ وَأُعْطِيَ خَوَاتِيمَ سُورَةِ الْبَقَرَةِ وَغُفِرَ لِمَنْ لَمْ يُشْرِكْ بِاللَّهِ مِنْ أُمَّتِهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Malik bin Mighwal]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ibnu Numair] dan [Zuhair bin Harb] semuanya dari [Abdullah bin Numair] dan lafazh mereka saling berdekatan. [Ibnu Numair] berkata, telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Malik bin Mighwal] dari [az-Zubair bin Adi] dari [Thalhah] dari [Murrah] dari [Abdullah] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan maka beliau dihentikan di Sidrah al-Muntaha, (yaitu tempat) yang terletak di langit keenam. Sesuatu yang naik dari bumi akan bermuara di sana dan ditahan padanya. Dan sesuatu dari atasnya berhenti padanya, lalu ditahan padanya.\" Allah berfirman: '(Muhammad melihat Jibril) ketika Sidratil Muntaha diliputi oleh sesuatu yang meliputinya) ' (Qs. An Najm: 16). Abdullah berkata lagi, \"Yaitu hamparan dari emas.\" Dia berkata lagi, \"Lalu Rasulullah shallallahu 'alaihi wasallam diberi tiga hal: shalat lima waktu, ayat-ayat penutup surat al-Baqarah, dan diampuni dosa-dosa besar milik orang yang tidak mensyirikkan Allah dengan sesuatu pun dari kalangan umat beliau.\""},{"p":"Muslim","n":250,"ar":"و حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا عَبَّادٌ وَهُوَ ابْنُ الْعَوَّامِ حَدَّثَنَا الشَّيْبَانِيُّ قَالَ سَأَلْتُ زِرَّ بْنَ حُبَيْشٍ عَنْ قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى }قَالَ أَخْبَرَنِي ابْنُ مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى جِبْرِيلَ لَهُ سِتُّ مِائَةِ جَنَاحٍ","trj":"Dan telah menceritakan kepada kami [Abu ar-Rabi' az-Zahrani] telah menceritakan kepada kami [Abbad] -yaitu Ibnu al-Awwam- telah menceritakan kepada kami [asy-Syaibani] dia berkata, \"Aku bertanya kepada [Zir bin Hubaisy] tentang firman Alah: '(Sehingga menjadilah jarak antara dia dengan Nabi Muhammad sejauh dua ujung busur panah atau lebih dekat lagi) ' (Qs. An Najm: 9). Perawi berkata, \" [Ibnu Mas'ud] mengabarkan kepadaku bahwa Nabi shallallahu 'alaihi wasallam melihat Jibril, ia mempunyai enam ratus sayap.\""},{"p":"Muslim","n":251,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الشَّيْبَانِيِّ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِقَالَ{ مَا كَذَبَ الْفُؤَادُ مَا رَأَى }قَالَ رَأَى جِبْرِيلَ عَلَيْهِ السَّلَام لَهُ سِتُّ مِائَةِ جَنَاحٍ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [asy-Syaibani] dari [Zirr] dari [Abdullah] dia berkata tentang firman-Nya: '(Hatinya tidak mendustakan sesuatu yang telah dia lihat) ' (Qs. An Najm: 11). Ibnu Mas'ud berkata, \"Nabi shallallahu 'alaihi wasallam melihat Jibril mempunyai enam ratus sayap.\""},{"p":"Muslim","n":252,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ سَمِعَ زِرَّ بْنَ حُبَيْشٍ عَنْ عَبْدِ اللَّهِقَالَ{ لَقَدْ رَأَى مِنْ آيَاتِ رَبِّهِ الْكُبْرَى }قَالَ رَأَى جِبْرِيلَ فِي صُورَتِهِ لَهُ سِتُّ مِائَةِ جَنَاحٍ","trj":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz al-Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman asy-Syaibani] dia mendengar [Zirr bin Hubaisy] dari [Abdullah] dia berkata tentang firman-Nya: '(Sungguh dia telah melihat ayat-ayat Rabbnya yang agung) ' (Qs. An Najm: 13). Ibnu Mas'ud berkata, \"Nabi shallallahu 'alaihi wasallam telah melihat Jibril dalam bentuk (asli) nya, dia mempunyai enam ratus sayap.\""},{"p":"Muslim","n":253,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }قَالَ رَأَى جِبْرِيلَ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Abdul Malik] dari [Atha'] dari [Abu Hurairah] tentang firman Allah: (Sungguh dia telah melihat ayat-ayat Rabbnya yang agung) ' (Qs. An Najm: 13). Abu Hurairah berkata, \"Beliau melihat malaikat Jibril.\""},{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Muslim","n":257,"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا زَكَرِيَّاءُ عَنْ ابْنِ أَشْوَعَ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَفَأَيْنَ قَوْله{ ثُمَّ دَنَا فَتَدَلَّى فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }قَالَتْ إِنَّمَا ذَاكَ جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِيهِ فِي صُورَةِ الرِّجَالِ وَإِنَّهُ أَتَاهُ فِي هَذِهِ الْمَرَّةِ فِي صُورَتِهِ الَّتِي هِيَ صُورَتُهُ فَسَدَّ أُفُقَ السَّمَاءِ","trj":"Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Zakariya'] dari [Ibnu Asywa'] dari [Amir] dari [Masruq] dia berkata, \"Aku berkata kepada [Aisyah], 'Lalu kita apakah firman Allah: '(Kemudian dia mendekat, lalu bertambah dekat lagi, maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi). Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan) ' (Qs. an-Najm: 8-10). Aisyah menjawab, '(Yang dimaksud ayat tersebut) adalah Jibril. Dia mendatangi Rasulullah dalam bentuk seorang laki-laki, dan pada kesempatan ini, dia mendatangi beliau dalam bentuknya yang sesungguhnya, sehingga dia menutupi ufuk langit'.\""},{"p":"Muslim","n":874,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْأَسْوَدَ يُحَدِّثُ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ وَالنَّجْمِ فَسَجَدَ فِيهَا وَسَجَدَ مَنْ كَانَ مَعَهُ غَيْرَ أَنَّ شَيْخًا أَخَذَ كَفًّا مِنْ حَصًى أَوْ تُرَابٍ فَرَفَعَهُ إِلَى جَبْهَتِهِ وَقَالَ يَكْفِينِي هَذَاقَالَ عَبْدُ اللَّهِ لَقَدْ رَأَيْتُهُ بَعْدُ قُتِلَ كَافِرًا","trj":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar [Al Aswad] menceritakan dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau pernah membaca wannajmi (surat annajm) lalu beliau sujud dan para sahabat yang bersamanya pun ikut sujud, kecuali seorang laki-laki tua, dia hanya mengambil sejumput kerikil atau tanah, dan mengangkat ke keningnya sambil berujar; \"Aku cukup begini saja.\" Abdullah berkomentar; \"Seingatku, dikemudian hari laki-laki tua itu mati dalam keadaan kafir.\""},{"p":"Muslim","n":875,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَيَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَابْنُ حُجْرٍ قَالَ يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا وَقَالَ الْآخَرُونَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ ابْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّهُ أَخْبَرَهُأَنَّهُ سَأَلَ زَيْدَ بْنَ ثَابِتٍ عَنْ الْقِرَاءَةِ مَعَ الْإِمَامِ فَقَالَ لَا قِرَاءَةَ مَعَ الْإِمَامِ فِي شَيْءٍ وَزَعَمَ أَنَّهُ قَرَأَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّجْمِ إِذَا هَوَى فَلَمْ يَسْجُدْ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Yahya bin Ayyub] dan [Qutaibah bin Sa'id] dan [Ibn Juhr]. Yahya bin Yahya mengatakan; telah mengabarkan kepada kami, sedangkan yang lain mengatakan; telah menceritakan kepada kami [Ismail yaitu Ibnu Ja'far] dari [Yazid bin Khushaifah] dari [Ibn Qusaith] dari ['Atha' bin Yasar], bahwa dia pernah memberitahukan kepadanya, ia bertanya kepada [Zaid bin Tsabit] tentang bacaan bersama imam, Zaid berujar; \"Tak ada bacaan bersama imam.\" seingatnya, ia pernah menyetorkan hafalan kepada Rasulullah shallallahu 'alaihi wasallam ayat Wannajmi (surat annajm), namun beliau tidak bersujud."},{"p":"Nasa'i","n":446,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ وَإِلَيْهَا يَنْتَهِي مَا عُرِجَ بِهِ مِنْ تَحْتِهَا وَإِلَيْهَا يَنْتَهِي مَا أُهْبِطَ بِهِ مِنْ فَوْقِهَا حَتَّى يُقْبَضَ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ فَأُعْطِيَ ثَلَاثًا الصَّلَوَاتُ الْخَمْسُ وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ وَيُغْفَرُ لِمَنْ مَاتَ مِنْ أُمَّتِهِ لَا يُشْرِكُ بِاللَّهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Yahya bin Adam] dia berkata; Telah menceritakan kepada kami [Malik bin Mighwal] dari [Zubair bin 'Adi] dari [Thalhah bin Musharrif] dari [Murrah] dari [Abdulah] dia berkata; \" Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan beliau sampai ke Sidratul Muntaha, yaitu satu tempat di langit yang ke enam dan sampai di situlah berakhirnya semua yang naik dari bawah dan sampai di situ pula semua yang turun dari atas hingga dapat terpegang. Nabi shallallahu 'alaihi wasallam kemudian membacakan ayat: \"Ketika Sidratul Muntaha diliputi oleh sesuatu yang meliputinya\" (Qs. An-Najm (53): 16) Rasulullah shallallahu 'alaihi wasallam bersabda: \" (Yang meliputi Sidratul Muntaha) adalah kupu-kupu dari emas, lalu aku diberi tiga hal, yaitu shalat lima waktu, akhir-akhir surat Al Baqarah, dan orang yang mati dari umatku diampuni, asalkan tidak menyekutukan Allah Azza Wa Jalla dengan sesuatupun.\" "},{"p":"Nasa'i","n":947,"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ عَبْدِ الْحَمِيدِ بْنِ مَيْمُونِ بْنِ مِهْرَانَ قَالَ حَدَّثَنَا ابْنُ حَنْبَلٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ جَعْفَرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ عَنْ أَبِيهِ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ سُورَةَ النَّجْمِ فَسَجَدَ وَسَجَدَ مَنْ عِنْدَهُ فَرَفَعْتُ رَأْسِي وَأَبَيْتُ أَنْ أَسْجُدَ وَلَمْ يَكُنْ يَوْمَئِذٍ أَسْلَمَ الْمُطَّلِبُ","trj":"Telah mengabarkan kepada kami [Abdul Malik Abdul Hamid bin Maimun bin Mihran] dia berkata; telah menceritakan kepada kami [Ibnu Hambali] dia berkata; Telah mengabarkan kepada kami [Ibrahim bin Khalid] dia berkata; telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Ibnu Thawus] dari [Ikrimah bin Khalid] dari [Ja'far bin Al Muthallib bin Abu Wada'ah] dari [Bapaknya] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam pernah membaca surat An-Najm di Makkah, dan beliau Shallallallahu'alaihi wasallam sujud dengan diikuti oleh orang di sekitarnya. Namun aku mengangkat kepalaku dan enggan untuk sujud waktu itu Al Muthallib belum masuk Islam."},{"p":"Nasa'i","n":948,"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ النَّجْمَ فَسَجَدَ فِيهَا","trj":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] bahwa Rasulullah Shallallallahu'alaihi wasallam pernah membaca surat An Najm, lantas beliau sujud."},{"p":"Nasa'i","n":949,"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّهُ سَأَلَ زَيْدَ بْنَ ثَابِتٍ عَنْ الْقِرَاءَةِ مَعَ الْإِمَامِ فَقَالَ لَا قِرَاءَةَ مَعَ الْإِمَامِ فِي شَيْءٍوَزَعَمَ أَنَّهُ قَرَأَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّجْمِ إِذَا هَوَى فَلَمْ يَسْجُدْ","trj":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dia adalah Ibnu Ja'far dari [Yazid bin Khushaifah] dari [Yazid bin Abdullah bin Qusaith] dari ['Atha bin Yasar] bahwa dia pernah bertanya kepada Zaid bin Tsabit tentang membaca bersama imam, maka [Zaid] berkata; \"Tidak ada bacaan saat imam membaca dan dia beranggapan bahwa ia pernah membaca di depan Rasulullah Shallallallahu'alaihi wasallam surat An Najm namun beliau tidak sujud.\""},{"p":"Tirmidzi","n":519,"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عُمَرَ الدِّمَشْقِيِّ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَسَجَدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى عَشْرَةَ سَجْدَةً مِنْهَا الَّتِي فِي النَّجْمِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عُمَرَ وَهُوَ ابْنُ حَيَّانَ الدِّمَشْقِيُّ قَال سَمِعْتُ مُخْبِرًا يُخْبِرُ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِلَفْظِهِ قَالَ أَبُو عِيسَى وَهَذَا أَصَحُّ مِنْ حَدِيثِ سُفْيَانَ بْنِ وَكِيعٍ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبٍ قَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ وَابْنِ مَسْعُودٍ وَزَيْدِ بْنِ ثَابِتٍ وَعَمْرِو بْنِ الْعَاصِ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي الدَّرْدَاءِ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عُمَرَ الدِّمَشْقِيِّ","trj":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Amru bin Al Harits] dari [Sa'id bin Abu Hilal] dari [Umar Ad Dimasyqi] dari [Ummi Darda'] dari [Abu Darda'] dia berkata, saya pernah sujud (tilawah) bersama Rasulullah Sallallaahu 'alaihi wasallam sebanyak sebelas kali, diantaranya ayat yang ada dalam surat An Najm. Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Umar] (yaitu Ibnu Hayyan Al Dimasyqi) dia berkata, saya mendengar [seseorang] mengabarkan dari [Ummi Darda'] dari [Abu Darda'] dari Nabi Sallallaahu 'alaihi wasallam seperti hadits diatas dengan lafadz yang sama. Abu 'Isa berkata, riwayat ini lebih shahih dari riwayat Sufyan bin Waki'. (perawi) berkata, dan dalam bab ini (ada juga riwayat -pent) dari Ali, Abu Hurairah, Ibnu Mas'ud, Zaid bin Tsabit, dan Amru bin Ash. Abu 'Isa berkata, hadits Abu Darda' adalah hadits gharib, tidak kami ketahui kecuali dari riwayat Sa'id bin Abu Hilal dari Umar Al Dimasyqi."},{"p":"Tirmidzi","n":524,"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْبَزَّازُ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا أَبِي عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَسَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا يَعْنِي النَّجْمَ وَالْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْجِنُّ وَالْإِنْسُقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ يَرَوْنَ السُّجُودَ فِي سُورَةِ النَّجْمِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ لَيْسَ فِي الْمُفَصَّلِ سَجْدَةٌ وَهُوَ قَوْلُ مَالِكِ بْنِ أَنَسٍ وَالْقَوْلُ الْأَوَّلُ أَصَحُّ وَبِهِ يَقُولُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","trj":"Telah menceritakan kepada kami [Harun bin Abdullah Al Bazaz Al Baghdadi] telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami [ayahku] dari [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata, Rasulullah Sallallahu 'alaihi wasallam sujud tilawah pada surat An Najm, demikian juga kaum muslimin, orang-orang kafir Quraisy, jin dan manusia (Ketika Rasul masih di Makkah. Pent) (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu Mas'ud dan Abu Hurairah. Abu 'Isa berkata, Hadits Ibnu Abbas ialah hadits hasan shahih dan diamalkan oleh ahli ilmu, mereka berpendapat adanya sujud tilawah dalam surat An najm. Sedangkan sebagian ahli ilmu dari para sahabat Nabi shallallahu 'alaihi wasallam berpendapat tidak adanya sujud tilawah pada Al Mufashsal (dari surat Qaf sampai akhir mushaf. Pent) demikian juga pendapat Malik bin Anas. Namun pendapat yang pertama lebih kuat, ini merupakan pendapatnya Ats Tsaury, Ibnu Al Mubarak, Syafi'i, Ahmad dan Ishaq."},{"p":"Tirmidzi","n":525,"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَرَأْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ فَلَمْ يَسْجُدْ فِيهَاقَالَ أَبُو عِيسَى حَدِيثُ زَيْدِ بْنِ ثَابِتٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَتَأَوَّلَ بَعْضُ أَهْلِ الْعِلْمِ هَذَا الْحَدِيثَ فَقَالَ إِنَّمَا تَرَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السُّجُودَ لِأَنَّ زَيْدَ بْنَ ثَابِتٍ حِينَ قَرَأَ فَلَمْ يَسْجُدْ لَمْ يَسْجُدْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا السَّجْدَةُ وَاجِبَةٌ عَلَى مَنْ سَمِعَهَا فَلَمْ يُرَخِّصُوا فِي تَرْكِهَا وَقَالُوا إِنْ سَمِعَ الرَّجُلُ وَهُوَ عَلَى غَيْرِ وُضُوءٍ فَإِذَا تَوَضَّأَ سَجَدَ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَأَهْلِ الْكُوفَةِ وَبِهِ يَقُولُ إِسْحَقُ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِنَّمَا السَّجْدَةُ عَلَى مَنْ أَرَادَ أَنْ يَسْجُدَ فِيهَا وَالْتَمَسَ فَضْلَهَا وَرَخَّصُوا فِي تَرْكِهَا إِنْ أَرَادَ ذَلِكَ وَاحْتَجُّوا بِالْحَدِيثِ الْمَرْفُوعِ حَدِيثِ زَيْدِ بْنِ ثَابِتٍ حَيْثُ قَالَ قَرَأْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ فَلَمْ يَسْجُدْ فِيهَا فَقَالُوا لَوْ كَانَتْ السَّجْدَةُ وَاجِبَةً لَمْ يَتْرُكْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا حَتَّى كَانَ يَسْجُدَ وَيَسْجُدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحْتَجُّوا بِحَدِيثِ عُمَرَ أَنَّهُ قَرَأَ سَجْدَةً عَلَى الْمِنْبَرِ فَنَزَلَ فَسَجَدَ ثُمَّ قَرَأَهَا فِي الْجُمُعَةِ الثَّانِيَةَ فَتَهَيَّأَ النَّاسُ لِلسُّجُودِ فَقَالَ إِنَّهَا لَمْ تُكْتَبْ عَلَيْنَا إِلَّا أَنْ نَشَاءَ فَلَمْ يَسْجُدْ وَلَمْ يَسْجُدُوا فَذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَى هَذَا وَهُوَ قَوْلُ الشَّافِعِيِّ وَأَحْمَدَ","trj":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi'b] dari [Yazid bin Abdullah bin Qusaith] dari ['Atha' bin Yasar] dari [Zaid bin Tsabit] dia berkata, saya membaca surat An najm dihadapan Rasulullah Sallallahu 'alaihi wasallam, namun beliau tidak sujud (tilawah). Abu 'Isa berkata, hadits Zaid bin Tsabit adalah hadits hasan shahih. sebagian ahlul ilmi memberikan penjelasan tentang hadits ini bahwa tidak sujudnya Nabi Shalallahu 'alaihi wa salam dikarenakan Zaid bin Tsabit, selaku qari' tidak sujud, mereka juga berpendapat bahwa sujud tilawah hukumnya wajib bagi siapa saja yang mendengar tanpa memberikan rukhshah didalamnya, bahkan mereka berkata, jika seseorang mendengarnya dalam keadaan tidak berwudlu' kemudian berwudlu, maka wajib baginya bersujud, perkataan ini merupakan pendapat Sufyan Ats Tsauri dan Ahli Kufah serta Ishaq. Sebagian dari ahlul ilmi berpendapat sujud tilawah disyare'atkan bagi siapa yang ingin bersujud dan mengharapkan keutamaan serta boleh juga untuk tidak dikerjakan. Mereka berhujjah dengan hadits shahih yaitu hadits Zaid bin Tsabit yang berkata, saya membaca surat An najm dihadapan Rasulullah Sallallahu 'alaihi wasallam, namun beliau tidak sujud (tilawah). Mereka juga berhujjah dengan hadits yang diriwayatkan oleh Umar, bahwasanya beliau membaca ayat As Sajdah di atas mimbar, lalu beliau turun dan langsung bersujud, kemudian membacanya lagi pada Jum'at berikutnya tatkala orang-orang bersiap-siap untuk bersujud, beliau bersabda: \"Sesungguhnya sujud tilawah tidak diwajibkan atas kita, hanya bagi siapa yang ingin melakukannya.\" Pada waktu itu beliau tidak sujud, demikian juga dengan orang-orang. Oleh karena itu sebagian ahlul ilmi berpegang pada pendapat ini, juga merupakan pendapatnya Syafi'i dan Ahmad."},{"p":"Tirmidzi","n":925,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلَّبِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِ فَقَالَتْ عَائِشَةُ يَرْحَمُهُ اللَّهُ لَمْ يَكْذِبْ وَلَكِنَّهُ وَهِمَ إِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مَاتَ يَهُودِيًّا إِنَّ الْمَيِّتَ لَيُعَذَّبُ وَإِنَّ أَهْلَهُ لَيَبْكُونَ عَلَيْهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَقَرَظَةَ بْنِ كَعْبٍ وَأَبِي هُرَيْرَةَ وَابْنِ مَسْعُودٍ وَأُسَامَةَ بْنِ زَيْدٍ قَالَ أَبُو عِيسَى حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عَائِشَةَ وَقَدْ ذَهَبَ أَهْلُ الْعِلْمِ إِلَى هَذَا وَتَأَوَّلُوا هَذِهِ الْآيَةَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }وَهُوَ قَوْلُ الشَّافِعِيِّ","trj":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami ['Abbad bin 'Abbad Al Muhallabi] dari [Muhammad bin 'Amr] dari [Yahya bin Abdurrahman] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya mayit itu diadzab karena tangisan keluarganya atas (kematian) nya.\" ['Aisyah] berkata; -Semoga Allah merahmati (Ibnu Umar) - dia tidak bohong namun salah mengucapkan, sebenarnya Rasulullah shallallahu 'alaihi wasallam berkata demikian kepada seorang lelaki yang mati dalam agama Yahudi yaitu sabda beliau, \"Sesungguhnya si mayit ini akan diadzab, dan keluarganya akan menangisinya.\" Hadits semakna diriwayatkan dari Ibnu Abbas, Qaradlah bin Ka'ab, Abu Hurairah, Ibnu Mas'ud dan Usamah bin Zaid. Abu 'Isa berkata; \"Hadits 'Aisyah merupakan hadits hasan shohih dan hadits ini telah diriwayatkan melalui lebih dari satu jalur dari 'Aisyah. Sebagian ulama yaitu Syafi'i berpendapat berdasarkan hadits ini dengan menta'wilkan ayat; \"Bahwasanya seorang yang berdosa tidak akan memikul dosa orang lain.\" (Qs. An Najm: 38) "},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."},{"p":"Tirmidzi","n":3031,"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِ اللَّهِ{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى عِنْدَ سِدْرَةِ الْمُنْتَهَى }{ فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى }قَالَ ابْنُ عَبَّاسٍ قَدْ رَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Ibnu Abbas] mengenai firman Allah: \"Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain, (yaitu) di Sidratil Muntaha\" (QS. Nnajm 13-14) \"Lalu dia menyampaikan kepada hambaNya (Muhammad) apa yang telah Allah wahyukan.\" (QS. ANnajm; 10) \"Maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi).\" (QS. Annajm 9), Ibnu Abbas berkata; Nabi shallallahu 'alaihi wasallam telah melihatNya. Abu Isa berkata; hadits ini adalah hadits hasan."},{"p":"Tirmidzi","n":3032,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ أَبِي رِزْمَةَ وَأَبُو نُعَيْمٍ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ مَا كَذَبَ الْفُؤَادُ مَا رَأَى }قَالَ رَآهُ بِقَلْبِهِقَالَ هَذَا حَدِيثٌ حَسَنٌ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Abdur Razzaq] dan [Ibnu Abu Rizmah] serta [Abu Nu'aim] dari [Israil] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas], ia berkomentar tentang ayat; \"Hatinya tidak mendustakan apa yang telah dilihatnya.\" (QS. ANnajm 11), Ia berkata; ia melihatNya dengan hatinya. Abu Isa berkata; hadits hasan."},{"p":"Tirmidzi","n":3034,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى وَابْنُ أَبِي رِزْمَةَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ{ مَا كَذَبَ الْفُؤَادُ مَا رَأَى }قَالَ رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِبْرِيلَ فِي حُلَّةٍ مِنْ رَفْرَفٍ قَدْ مَلَأَ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abdu bin Humaid] telah menceritakan kepada kami ['Ubaidullah bin Musa] serta [Ibnu Abu Rizmah] dari [Israil] dari [Abu Ishaq] dari [Abdur Rahman bin Yazid] dari [Abdullah], mengenai ayat; \"Hatinya tidak mendustakan apa yang telah dilihatnya.\" (QS. ANnajm 11), Ia berkata; Rasulullah shallallahu 'alaihi wasallam melihat Jibril memakai perhiasan dari permadani yang telah memenuhi antara langit dan bumi. Abu Isa berkata; hadits ini adalah hadits hasan shahih."},{"p":"Tirmidzi","n":3035,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ الْبَصْرِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ{ الَّذِينَ يَجْتَنِبُونَ كَبَائِرَ الْإِثْمِ وَالْفَوَاحِشَ إِلَّا اللَّمَمَ }قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ تَغْفِرْ اللَّهُمَّ تَغْفِرْ جَمَّاوَأَيُّ عَبْدٍ لَكَ لَا أَلَمَّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ زَكَرِيَّا بْنِ إِسْحَقَ","trj":"Telah menceritakan kepada kami [Ahmad bin Utsman Al Bashri] telah menceritakan kepada kami [Abu 'Ashim] dari [Zakariya bin Ishaq] dari ['Amr bin Dinar] dari ['Atho`] dari [Ibnu Abbas] mengenai ayat: \"(Yaitu) orang-orang yang menjauhi dosa-dosa besar dan perbuatan keji yang selain dari kesalahan-kesalahan kecil.\" (QS. Annajm 32), Ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Ya Allah, apabila engkau mengampuni maka Engkau banyak mengampuni, siapakah hamba yang tidak pernah melakukan dosa-dosa kecil?\" Abu Isa berkata; hadits ini adalah hadits hasan shahih gharib, kami tidak mengetahuinya kecuali dari hadits Zakariya bin Ishaq."}]};
